import UIKit

@main
class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return false }
        if components.path == "/reset-password", let token = components.queryItems?.first(where: { $0.name == "token" })?.value {
            // Navigate to the password reset screen with the token
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            guard let resetViewController = storyboard.instantiateViewController(withIdentifier: "ResetPasswordViewController") as? ResetPasswordViewController else { return false }
            resetViewController.resetToken = token
            
            if let rootViewController = app.keyWindow?.rootViewController {
                rootViewController.present(resetViewController, animated: true, completion: nil)
            }
        }
        return true
    }

